import random

def extract_random_subset(dimensions: list[int], intervals: list[int] = None) -> list:
    def build_original_array(dims):
        if not dims:
            return random.randint(0, 100)
        return [build_original_array(dims[1:]) for _ in range(dims[0])]

    original_array = build_original_array(dimensions)

    if intervals is None:
        intervals = []
        for d in dimensions:
            if d > 0:
                start = random.randint(0, d - 1)
                end = random.randint(start + 1, d)
                intervals.extend([start, end])
            else:
                intervals.extend([0, 0])

    def slice_array(arr, depth):
        if depth == len(dimensions):
            return arr
        start = intervals[depth * 2]
        end = intervals[depth * 2 + 1]
        sliced = arr[start:end]
        if depth == len(dimensions) - 1:
            return sliced
        return [slice_array(item, depth + 1) for item in sliced]

    return slice_array(original_array, 0)
