def get_job_exit_code(job_id):
    try:
        result = subprocess.run(
            ["job_status_command", str(job_id)],
            capture_output=True,
            text=True,
            check=True
        )
        output = result.stdout

        state_match = re.search(r'(?i)state[\s:=]+([a-z0-9_]+)', output)
        if state_match:
            logging.info("Job %s state: %s", job_id, state_match.group(1))
        else:
            logging.info("Job %s state information: %s", job_id, output.strip())

        exit_code_match = re.search(r'(?i)exit_?code[\s:=]+(\d+)', output)
        if exit_code_match:
            return int(exit_code_match.group(1))

        logging.warning("Could not extract exit code for job %s.", job_id)
        return None

    except subprocess.CalledProcessError as e:
        logging.error("Command execution failed for job %s: %s", job_id, e)
        return None
    except Exception as e:
        logging.error("An error occurred while processing job %s: %s", job_id, e)
        return None

