import numpy as np
import itertools

def process_data(data, method, values=None):
    if values is None:
        values = np.zeros_like(data)

    exclude = eval(method)

    def curve(data_arr, x, y, ey, eyl, vals):
        new_arr = np.copy(data_arr)
        if new_arr.dtype.names is not None:
            for k in ['x', 'y', 'ey', 'eyl']:
                new_arr[k] = vals[k]
        else:
            new_arr[x, y, ey, eyl] = vals[x, y, ey, eyl]
        return new_arr

    total_sum = 0

    if data.dtype.names is not None and set(['x', 'y', 'ey', 'eyl']).issubset(data.dtype.names):
        # Structured array scenario
        new_data = curve(data, 'x', 'y', 'ey', 'eyl', values)
        for row in itertools.chain(data):
            if exclude(row['x'], row['y'], row['ey'], row['eyl']):
                total_sum += row['value'] if 'value' in data.dtype.names else 1
    else:
        # Multidimensional array scenario (4D)
        if data.ndim == 4:
            shape_iters = [range(dim) for dim in data.shape]
            for x, y, ey, eyl in itertools.product(*shape_iters):
                if exclude(x, y, ey, eyl):
                    total_sum += data[x, y, ey, eyl]
                    # Fulfilling the requirement to use the 'curve' function
                    _ = curve(data, x, y, ey, eyl, values)

    return total_sum
