            'x': obj.get('x') if is_dict else getattr(obj, 'x', 0),
            'y': obj.get('y') if is_dict else getattr(obj, 'y', 0),
            'time': obj.get('time') if is_dict else getattr(obj, 'time', 0.0),
            'note_type': obj.get('note_type') if is_dict else getattr(obj, 'note_type', None)
        }

        curve = obj.get('curve') if is_dict else getattr(obj, 'curve', None)
        if curve is not None:
            note['curve'] = curve

        repeat = obj.get('repeat') if is_dict else getattr(obj, 'repeat', None)
        if repeat is not None:
            note['repeat'] = repeat

        notes.append(note)

    notes.sort(key=lambda n: n['time'] if n['time'] is not None else 0)

    return notes

