def convert_gff3_to_gtf(input_file, output_file, dialect='standard'):
    open_func = gzip.open if input_file.endswith('.gz') else open

    with open_func(input_file, 'rt', encoding='utf-8') as f_in, open(output_file, 'w', encoding='utf-8') as f_out:
        for line in f_in:
            if line.startswith('#'):
                if line.startswith('##gff-version'):
                    f_out.write('##gtf-version 2.2\n')
                elif not line.startswith('##'):
                    f_out.write(line)
                continue

            cols = line.strip('\n').split('\t')
            if len(cols) != 9:
                continue

            seqid, source, feature, start, end, score, strand, phase, attributes = cols

            attr_dict = {}
            for attr in attributes.split(';'):
                attr = attr.strip()
                if not attr:
                    continue
                if '=' in attr:
                    key, value = attr.split('=', 1)
                    attr_dict[key.strip()] = urllib.parse.unquote(value.strip())

            gtf_attrs = {}
            if dialect == 'standard':
                if 'ID' in attr_dict:
                    if feature == 'gene':
                        gtf_attrs['gene_id'] = attr_dict['ID']
                    elif feature in ['transcript', 'mRNA', 'tRNA', 'rRNA', 'ncRNA']:
                        gtf_attrs['transcript_id'] = attr_dict['ID']
                        if 'Parent' in attr_dict:
                            gtf_attrs['gene_id'] = attr_dict['Parent']

                if 'Parent' in attr_dict and feature in ['exon', 'CDS', 'start_codon', 'stop_codon']:
                    gtf_attrs['transcript_id'] = attr_dict['Parent']
            elif dialect == 'ensembl':
                if 'gene_id' in attr_dict:
                    gtf_attrs['gene_id'] = attr_dict['gene_id']
                if 'transcript_id' in attr_dict:
                    gtf_attrs['transcript_id'] = attr_dict['transcript_id']

            for k, v in attr_dict.items():
                if k not in gtf_attrs:
                    gtf_attrs[k] = v

            gtf_attr_strs = []

            if 'gene_id' in gtf_attrs:
                gtf_attr_strs.append(f'gene_id "{gtf_attrs.pop("gene_id")}"')
            if 'transcript_id' in gtf_attrs:
                gtf_attr_strs.append(f'transcript_id "{gtf_attrs.pop("transcript_id")}"')

            for key, value in gtf_attrs.items():
                for val in value.split(','):
                    gtf_attr_strs.append(f'{key} "{val}"')

            cols[8] = '; '.join(gtf_attr_strs) + ';'
            f_out.write('\t'.join(cols) + '\n')
