import hashlib
from typing import Any, Optional

class CryptoHashFunction:
    def __init__(self, state: Any = None, algo: str = 'sha256'):
        self._state = state
        self._algo = algo

    def __call__(self, data: str, algo: Optional[str] = None) -> str:
        if self._state is not None:
            h = self._state.copy()
        else:
            h = hashlib.new(algo if algo is not None else self._algo)
        h.update(data.encode('utf-8'))
        return h.hexdigest()

    def clone(self, initial_substring: str, algo: Optional[str] = None) -> 'CryptoHashFunction':
        if self._state is not None:
            h = self._state.copy()
            new_algo = self._algo
        else:
            new_algo = algo if algo is not None else self._algo
            h = hashlib.new(new_algo)

        h.update(initial_substring.encode('utf-8'))
        return CryptoHashFunction(state=h, algo=new_algo)

