def terminate_process(pid, timeout=10.0, initial_sleep=0.1, max_sleep=2.0, factor=2.0):
    def is_running(p):
        if sys.platform == "win32":
            try:
                out = subprocess.check_output(
                    ["tasklist", "/FI", f"PID eq {p}", "/NH"], 
                    text=True,
                    stderr=subprocess.DEVNULL
                )
                return str(p) in out.split()
            except Exception:
                return False
        else:
            try:
                os.kill(p, 0)
                return True
            except OSError:
                return False

    if not is_running(pid):
        return -1

    start_time = time.time()
    current_sleep = initial_sleep

    while True:
        if sys.platform == "win32":
            subprocess.run(
                ["taskkill", "/PID", str(pid)], 
                stdout=subprocess.DEVNULL, 
                stderr=subprocess.DEVNULL
            )
        else:
            try:
                os.kill(pid, signal.SIGTERM)
            except OSError:
                pass

        if not is_running(pid):
            return 0

        elapsed = time.time() - start_time
        if elapsed >= timeout:
            break

        time.sleep(min(current_sleep, timeout - elapsed))
        current_sleep = min(current_sleep * factor, max_sleep)

    return 1

