import re
import json
from collections import Counter

def extract_text_from_pdf(pdf_path):
    try:
        result = subprocess.run(
            ['pdftotext', pdf_path, '-'],
            capture_output=True,
            text=True,
            check=True
        )
        return result.stdout
    except FileNotFoundError:
        raise RuntimeError("pdftotext is not installed or not in PATH.")
    except subprocess.CalledProcessError as e:
        raise RuntimeError(f"Error extracting text: {e.stderr}")

def tokenize(text):
    return re.findall(r'\b\w+\b', text.lower())

def create_bow(tokens):
    return dict(Counter(tokens))

def write_bow_to_file(bow, output_path):
    with open(output_path, 'w', encoding='utf-8') as f:
        json.dump(bow, f, indent=4)

def main():
    if len(sys.argv) != 3:
        print(f"Usage: python {sys.argv[0]} <input_pdf_path> <output_json_path>")
        sys.exit(1)

    input_pdf = sys.argv[1]
    output_file = sys.argv[2]

    text = extract_text_from_pdf(input_pdf)
    tokens = tokenize(text)
    bow = create_bow(tokens)
    write_bow_to_file(bow, output_file)

if __name__ == '__main__':
    main()
