import shelve

def create_data_filter(db_path, allowed_types):
    class DataFilter:
        def __init__(self, path, types):
            self.path = path
            self.types = tuple(types)

        def record(self, key, data):
            if isinstance(data, self.types):
                with shelve.open(self.path) as db:
                    db[key] = data
                return True
            return False

        def playback(self, key):
            with shelve.open(self.path) as db:
                data = db.get(key)
                if isinstance(data, self.types):
                    return data
            return None

        def playback_all(self):
            with shelve.open(self.path) as db:
                return {k: v for k, v in db.items() if isinstance(v, self.types)}

    return DataFilter(db_path, allowed_types)
