import logging

def generate_and_configure_ssh_keys(root_fs: str, logger_name: str) -> bool:
    logger = logging.getLogger(logger_name)
    ssh_dir = os.path.join(root_fs, 'etc', 'ssh')
    sshd_config_path = os.path.join(ssh_dir, 'sshd_config')

    keys_to_generate = [
        ('rsa1', 'ssh_host_key'),
        ('rsa', 'ssh_host_rsa_key'),
        ('dsa', 'ssh_host_dsa_key')
    ]

    try:
        if not os.path.exists(ssh_dir):
            os.makedirs(ssh_dir, exist_ok=True)
            logger.debug(f"Created SSH directory at {ssh_dir}")

        for key_type, key_filename in keys_to_generate:
            key_path = os.path.join(ssh_dir, key_filename)

            if os.path.exists(key_path):
                try:
                    os.remove(key_path)
                    if os.path.exists(f"{key_path}.pub"):
                        os.remove(f"{key_path}.pub")
                except OSError as e:
                    logger.error(f"Failed to remove existing key {key_path}: {e}")
                    continue

            logger.debug(f"Generating {key_type} key at {key_path}")

            cmd = [
                'ssh-keygen',
                '-q',
                '-t', key_type,
                '-f', key_path,
                '-N', ''
            ]

            try:
                subprocess.run(cmd, check=True, capture_output=True, text=True)
                logger.debug(f"Successfully generated {key_type} key.")
            except subprocess.CalledProcessError as e:
                logger.error(f"Failed to generate {key_type} key. Error: {e.stderr.strip()}")
                continue

        config_lines = []
        if os.path.exists(sshd_config_path):
            try:
                with open(sshd_config_path, 'r') as f:
                    config_lines = f.readlines()
            except IOError as e:
                logger.error(f"Failed to read {sshd_config_path}: {e}")
                return False

        hostkey_directives = [
            'HostKey /etc/ssh/ssh_host_key\n',
            'HostKey /etc/ssh/ssh_host_rsa_key\n',
            'HostKey /etc/ssh/ssh_host_dsa_key\n'
        ]

        cleaned_config = []
        for line in config_lines:
            if not any(line.strip() == directive.strip() for directive in hostkey_directives):
                cleaned_config.append(line)

        if cleaned_config and not cleaned_config[-1].endswith('\n'):
            cleaned_config.append('\n')

        cleaned_config.extend(hostkey_directives)

        try:
            with open(sshd_config_path, 'w') as f:
                f.writelines(cleaned_config)
            logger.debug(f"Successfully configured {sshd_config_path} with new HostKeys.")
        except IOError as e:
            logger.error(f"Failed to write to {sshd_config_path}: {e}")
            return False

        return True

    except Exception as e:
        logger.error(f"An unexpected error occurred: {str(e)}")
        return False
