import warnings

def deprecated_attribute(old_name, new_name, version):
    def _issue_deprecation_warning():
        warnings.warn(
            f"Attribute '{old_name}' is deprecated since version {version}. "
            f"Please use '{new_name}' instead.",
            DeprecationWarning,
            stacklevel=3
        )

    @property
    def prop(self):
        _issue_deprecation_warning()
        return getattr(self, new_name)

    @prop.setter
    def prop(self, value):
        _issue_deprecation_warning()
        setattr(self, new_name, value)

