                x0, x1 = x_coords[i], x_coords[i + 1]
                if x0 <= x_target <= x1:
                    y0, y1 = y_coords[i], y_coords[i + 1]
                    if x0 == x1:
                        y_target = y0
                    else:
                        y_target = y0 + (x_target - x0) * (y1 - y0) / (x1 - x0)
                    interpolated_results.append((x_target, y_target))
                    break
    return interpolated_results

def perform_search_and_replace(data, search_term, replace_term):
    if isinstance(data, dict):
        return {k: perform_search_and_replace(v, search_term, replace_term) for k, v in data.items()}
    elif isinstance(data, list):
        return [perform_search_and_replace(v, search_term, replace_term) for v in data]
    elif isinstance(data, tuple):
        return tuple(perform_search_and_replace(v, search_term, replace_term) for v in data)
    elif isinstance(data, set):
        return {perform_search_and_replace(v, search_term, replace_term) for v in data}
    else:
        return replace_term if data == search_term else data

def process_pickle_files(file1, file2, file3, out_file1, out_file2, default_target_x, search_val, replace_val):
    data1 = load_pickle_data(file1)
    data2 = load_pickle_data(file2)
    data3 = load_pickle_data(file3)

