    if isinstance(data3, list) and all(isinstance(x, (int, float)) for x in data3):
        target_x = data3

    interpolated_data = perform_linear_interpolation(data1, target_x)
    save_pickle_data(interpolated_data, out_file1)

    modified_data = perform_search_and_replace(data2, search_val, replace_val)
    save_pickle_data(modified_data, out_file2)

