import inspect
import collections

def execute_function(func_str, options):
    env = {
        'collections': collections,
        'namedtuple': collections.namedtuple,
    }

    keys_before = set(env.keys())
    exec(func_str, env)
    keys_after = set(env.keys())

    new_keys = keys_after - keys_before
    funcs = [env[k] for k in env if k in new_keys and inspect.isfunction(env[k])]

    if not funcs:
        return eval(func_str, env, options)

    target_func = funcs[0]
    sig = inspect.signature(target_func)

    if any(p.kind == inspect.Parameter.VAR_KEYWORD for p in sig.parameters.values()):
        return target_func(**options)

    kwargs = {k: v for k, v in options.items() if k in sig.parameters}
    return target_func(**kwargs)

