import re

def compile_template(_n):
    syntax_rules = {
        'ADD': '+',
        'SUB': '-',
        'MUL': '*',
        'DIV': '/',
        'MOD': '%',
        'POW': '**',
        'AND': 'and',
        'OR': 'or',
        'NOT': 'not',
        'EQ': '==',
        'NEQ': '!='
    }

    tokens = re.findall(r'[a-zA-Z_]\w*|\d+(?:\.\d+)?|[()\[\]]', _n)

    def parse_tokens(token_list):
        compiled = []
        while token_list:
            token = token_list.pop(0)

            if token in syntax_rules:
                compiled.append(syntax_rules[token])
            elif re.match(r'^[a-zA-Z_]\w*$', token):
                compiled.append(f'kwargs.get("{token}")')
            else:
                compiled.append(token)

        return " ".join(compiled)

    python_expr = parse_tokens(tokens)
    return eval(f"lambda **kwargs: {python_expr}")
