import sqlite3

def get_table_row_counts(db_path, table_names):
    if not table_names:
        return {}

    row_counts = {}
    reference_schema = None

    with sqlite3.connect(db_path) as conn:
        cursor = conn.cursor()

        for table in table_names:
            cursor.execute(f'PRAGMA table_info("{table}")')
            schema = [(col[1], col[2]) for col in cursor.fetchall()]

            if not schema:
                raise ValueError(f"Table '{table}' does not exist or has no columns.")

            if reference_schema is None:
                reference_schema = schema
            elif schema != reference_schema:
                raise ValueError(f"Tables have different schemas: mismatch at '{table}'.")

            cursor.execute(f'SELECT COUNT(*) FROM "{table}"')
            count = cursor.fetchone()[0]

            if count == 0:
                raise ValueError(f"Table '{table}' has zero rows.")

            row_counts[table] = count

    return row_counts

