import os
import shelve
import re

def build_index(directory_path):
    shelves = {}

    def startIndexer():
        shelves['invertedIndex'] = shelve.open('invertedIndex')
        shelves['forwardIndex'] = shelve.open('forwardIndex')
        shelves['idToUrl'] = shelve.open('idToUrl')

    def finishIndexer():
        if 'invertedIndex' in shelves: shelves['invertedIndex'].close()
        if 'forwardIndex' in shelves: shelves['forwardIndex'].close()
        if 'idToUrl' in shelves: shelves['idToUrl'].close()

    try:
        from nltk.stem import PorterStemmer
        stemmer = PorterStemmer()
        stem = stemmer.stem
    except ImportError:
        def stem(word):
            if word.endswith('ing'): return word[:-3]
            if word.endswith('ed'): return word[:-2]
            if word.endswith('s') and not word.endswith('ss'): return word[:-1]
            return word

    startIndexer()

    inverted_dict = {}
    doc_id = 1

    for root, _, files in os.walk(directory_path):
        for file_name in files:
            file_path = os.path.join(root, file_name)
            try:
                with open(file_path, 'r', encoding='utf-8') as f:
                    text = f.read()
            except Exception:
                continue

            doc_id_str = str(doc_id)
            url = f"file://{os.path.abspath(file_path)}"

            tokens = re.findall(r'\b\w+\b', text.lower())
            stemmed_tokens = [stem(token) for token in tokens]
            parsed_text = ' '.join(stemmed_tokens)

            shelves['forwardIndex'][doc_id_str] = parsed_text
            shelves['idToUrl'][doc_id_str] = url

            for term in set(stemmed_tokens):
                if term not in inverted_dict:
                    inverted_dict[term] = []
                inverted_dict[term].append(doc_id)

            doc_id += 1

    inverted_tuples = [(term, sorted(doc_ids)) for term, doc_ids in inverted_dict.items()]
    shelves['invertedIndex']['data'] = inverted_tuples

    finishIndexer()
