def adjust_volume(command: str) -> str:
    os_name = platform.system()
    try:
        if os_name == "Linux":
            if command == "up":
                subprocess.run(["amixer", "sset", "Master", "5%+"], capture_output=True)
            elif command == "down":
                subprocess.run(["amixer", "sset", "Master", "5%-"], capture_output=True)

            result = subprocess.run(["amixer", "sget", "Master"], capture_output=True, text=True)
            match = re.search(r"\[(\d+%)\]", result.stdout)
            if match:
                return match.group(1)
            return "Error: Could not determine current volume."

        elif os_name == "Darwin":
            if command == "up":
                subprocess.run(["osascript", "-e", "set volume output volume (output volume of (get volume settings) + 5)"], capture_output=True)
            elif command == "down":
                subprocess.run(["osascript", "-e", "set volume output volume (output volume of (get volume settings) - 5)"], capture_output=True)

            result = subprocess.run(["osascript", "-e", "output volume of (get volume settings)"], capture_output=True, text=True)
            if result.returncode == 0:
                return f"{result.stdout.strip()}%"
            return "Error: Could not determine current volume."
        else:
            return "Error: Unsupported operating system."

    except Exception:
        return "Error: Volume adjustment or retrieval failed."
