def analyze_hg_branches():
    cmd = ['hg', 'log', '-r', '0:tip', '-T', '{rev}|{node}|{parents}\n']
    try:
        output = subprocess.check_output(cmd, universal_newlines=True).strip()
    except subprocess.CalledProcessError:
        return

    if not output:
        return

    commit_parents = {}
    nodes_by_rev = {}
    lines = output.split('\n')

    for line in lines:
        parts = line.split('|')
        if len(parts) != 3:
            continue

        rev_str, node, parents_str = parts
        rev = int(rev_str)
        nodes_by_rev[rev] = node

        if parents_str:
            parent_revs = [int(p.split(':')[0]) for p in parents_str.strip().split()]
            parents = [nodes_by_rev[pr] for pr in parent_revs if pr != -1]
        else:
            parents = [nodes_by_rev[rev - 1]] if rev > 0 else []

        commit_parents[node] = parents

    active_branches = set()
    for line in lines:
        parts = line.split('|')
        if len(parts) != 3:
            continue

        rev_str, node, _ = parts

        for p_node in commit_parents[node]:
            if p_node in active_branches:
                active_branches.remove(p_node)

        active_branches.add(node)
        print(f"Commit {node} (rev {rev_str}): {len(active_branches)} branches")

