def modify_packet_layers(packet):
    if packet.haslayer('IP'):
        packet['IP'].ttl = 64
        del packet['IP'].chksum
    if packet.haslayer('TCP'):
        del packet['TCP'].chksum

    reconstructed_packet = None
    current_layer = packet

    while current_layer:
        single_layer = current_layer.copy()
        single_layer.remove_payload()

        single_layer.name = f"Renamed_{single_layer.name}"

        if hasattr(single_layer, 'chksum'):
            del single_layer.chksum

        if 'HTTP' not in single_layer.__class__.__name__:
            if reconstructed_packet is None:
                reconstructed_packet = single_layer
            else:
                reconstructed_packet = reconstructed_packet / single_layer

        current_layer = current_layer.payload

    return reconstructed_packet
