import json
import os
from urllib.parse import urlparse

class DataReader:
    def __init__(self, source: str, fail_on_missing_input: bool = True):
        self.source = source
        self.fail_on_missing_input = fail_on_missing_input

    def __iter__(self):
        parsed = urlparse(self.source)
        if parsed.scheme in ('s3', 'gs'):
            yield from self._read_bucket(parsed)
        else:
            yield from self._read_file()

    def _read_file(self):
        if not os.path.exists(self.source):
            if self.fail_on_missing_input:
                raise FileNotFoundError(f"Missing input file: {self.source}")
            return

        with open(self.source, 'r', encoding='utf-8') as f:
            for line in f:
                yield line

    def _read_bucket(self, parsed):
        if parsed.scheme == 's3':
            import boto3
            import botocore

            s3 = boto3.client('s3')
            try:
                obj = s3.get_object(Bucket=parsed.netloc, Key=parsed.path.lstrip('/'))
                for line in obj['Body'].iter_lines():
                    yield line.decode('utf-8') + '\n'
            except botocore.exceptions.ClientError as e:
                if e.response['Error']['Code'] in ('NoSuchKey', '404'):
                    if self.fail_on_missing_input:
                        raise FileNotFoundError(f"Missing S3 object: {self.source}")
                    return
                raise

        elif parsed.scheme == 'gs':
            from google.cloud import storage
            import google.api_core.exceptions

            client = storage.Client()
            bucket = client.bucket(parsed.netloc)
            blob = bucket.blob(parsed.path.lstrip('/'))
            try:
                contents = blob.download_as_text()
                for line in contents.splitlines(keepends=True):
                    yield line
            except google.api_core.exceptions.NotFound:
                if self.fail_on_missing_input:
                    raise FileNotFoundError(f"Missing GCS object: {self.source}")
                return

    def to_json(self) -> str:
        return json.dumps({
            "source": self.source,
            "fail_on_missing_input": self.fail_on_missing_input
        })

    @classmethod
    def from_json(cls, json_str: str) -> "DataReader":
        data = json.loads(json_str)
        return cls(
            source=data["source"],
            fail_on_missing_input=data.get("fail_on_missing_input", True)
        )

