def execute_function(func_name, args=None, kwargs=None):
    if args is None:
        args = ()
    if kwargs is None:
        kwargs = {}

    env = globals().copy()
    env['_args'] = args
    env['_kwargs'] = kwargs

    try:
        exec(f"_result = {func_name}(*_args, **_kwargs)", env)
        return env.get('_result')
    except Exception as e:
