    public static void CompileAndExecute(string sourceCode, string[] executionArgs)
    {
        using (CSharpCodeProvider provider = new CSharpCodeProvider())
        {
            CompilerParameters parameters = new CompilerParameters
            {
                GenerateInMemory = true,
                GenerateExecutable = true
            };

            parameters.ReferencedAssemblies.Add("System.dll");

            CompilerResults results = provider.CompileAssemblyFromSource(parameters, sourceCode);

            if (results.Errors.HasErrors)
            {
                foreach (CompilerError error in results.Errors)
                {
                    Console.Error.WriteLine($"Compilation Error: {error.ErrorText}");
                }
                return;
            }

            Assembly compiledAssembly = results.CompiledAssembly;
            MethodInfo entryPoint = compiledAssembly.EntryPoint;

            if (entryPoint != null)
            {
                object[] methodArgs = entryPoint.GetParameters().Length == 0 ? null : new object[] { executionArgs };
                entryPoint.Invoke(null, methodArgs);
            }
            else
            {
                Console.Error.WriteLine("No valid entry point (Main method) found in the compiled payload.");
            }
        }
    }
}
