CREATE OR REPLACE FUNCTION manage_dynamic_triggers()
RETURNS void AS $$
DECLARE
    trigger_rec RECORD;
    table_rec RECORD;
BEGIN
    EXECUTE 'CREATE LANGUAGE IF NOT EXISTS plpgsql';

    FOR trigger_rec IN 
        SELECT tg.tgname, rel.relname, ns.nspname
        FROM pg_trigger tg
        JOIN pg_class rel ON rel.oid = tg.tgrelid
        JOIN pg_namespace ns ON ns.oid = rel.relnamespace
        WHERE tg.tgname LIKE 'dyn_trig_%' AND tg.tgisinternal = false
    LOOP
        EXECUTE format(
            'DROP TRIGGER IF EXISTS %I ON %I.%I CASCADE', 
            trigger_rec.tgname, 
            trigger_rec.nspname, 
            trigger_rec.relname
        );
    END LOOP;

    FOR table_rec IN 
        SELECT table_schema, table_name 
        FROM information_schema.tables 
        WHERE table_schema = 'public' AND table_type = 'BASE TABLE'
    LOOP
        EXECUTE format(
            'CREATE TRIGGER %I AFTER INSERT OR UPDATE OR DELETE ON %I.%I FOR EACH ROW EXECUTE FUNCTION generic_trigger_handler()',
            'dyn_trig_' || table_rec.table_name,
            table_rec.table_schema,
            table_rec.table_name
        );
    END LOOP;
END;
$$ LANGUAGE plpgsql;

