import collections

def get_table_columns(cursor, table_name, columns=None, named_tuples=False):
    Column = collections.namedtuple('Column', ['name', 'data_type'])
    result = []

    try:
        cursor.execute(f"SHOW COLUMNS FROM {table_name}")
        rows = cursor.fetchall()

        for row in rows:
            col_name = row[0]
            col_data_type = row[1]

            if columns is not None and col_name not in columns:
                continue

            if named_tuples:
                result.append(Column(name=col_name, data_type=col_data_type))
            else:
                result.append((col_name, col_data_type))

        return result

    except Exception as e:
        print(f"An error occurred while retrieving columns: {e}")
        return []
