class CodeBlockCLI:
    def __init__(self):
        self.lines = []
        self.current_indent = 0

    def append(self, line):
        stripped = line.strip()

        if stripped.startswith(("elif ", "else:", "except ", "except:", "finally:")):
            self.current_indent = max(0, self.current_indent - 1)

        if stripped:
            self.lines.append("    " * self.current_indent + stripped)
        else:
            self.lines.append("")

        if stripped.endswith(":"):
            self.current_indent += 1
        elif stripped in ("pass", "break", "continue", "return") or stripped.startswith("return "):
            self.current_indent = max(0, self.current_indent - 1)

    def get_code(self):
        return "\n".join(self.lines)

    def run(self):
        code = self.get_code()
        print(code)
        exec(code, globals())

    def interact(self):
        print("Interactive Code Block CLI. Type 'run' to execute, 'clear' to clear, 'exit' to quit.")
        while True:
            try:
                prompt = "... " if self.current_indent > 0 else ">>> "
                user_input = input(prompt)

                if user_input.strip() == "exit":
                    break
                elif user_input.strip() == "run":
                    self.run()
                    self.lines.clear()
                    self.current_indent = 0
                elif user_input.strip() == "clear":
                    self.lines.clear()
                    self.current_indent = 0
                else:
                    self.append(user_input)
            except (EOFError, KeyboardInterrupt):
                print()
                break
