    def load_test_expectations(self) -> None:
        if not os.path.isfile(self.expectations_filepath):
            raise FileNotFoundError(f"Could not find expectations file: {self.expectations_filepath}")

        with open(self.expectations_filepath, 'r', encoding='utf-8') as file:
            self.expectations = json.load(file)

    def setup(self) -> None:
        self.setup_desktop_environment()
        self.load_test_expectations()

    def teardown(self) -> None:
        if self._display_process is not None:
            self._display_process.terminate()
            self._display_process.wait()
