import json
import ast

def deserialize(json_str: str, decode_keys: bool = False):
    if not decode_keys:
        return json.loads(json_str)

    def object_pairs_hook(pairs):
        result = {}
        for key, value in pairs:
            try:
                parsed_key = ast.literal_eval(key)
            except (ValueError, SyntaxError):
                parsed_key = key
            result[parsed_key] = value
        return result

    return json.loads(json_str, object_pairs_hook=object_pairs_hook)
