class AudioBookDatabase:
    def __init__(self, db_name="audiobooks.db"):
        self.conn = sqlite3.connect(db_name, check_same_thread=False)
        self.cursor = self.conn.cursor()
        self.cursor.execute('''
            CREATE TABLE IF NOT EXISTS progress (
                rfid_id TEXT PRIMARY KEY,
                position REAL
            )
        ''')
        self.conn.commit()

    def get_progress(self, rfid_id):
        self.cursor.execute("SELECT position FROM progress WHERE rfid_id = ?", (rfid_id,))
        result = self.cursor.fetchone()
        return result[0] if result else 0.0

    def save_progress(self, rfid_id, position):
        self.cursor.execute('''
            REPLACE INTO progress (rfid_id, position)
            VALUES (?, ?)
        ''', (rfid_id, position))
        self.conn.commit()

    def delete_progress(self, rfid_id):
        self.cursor.execute("DELETE FROM progress WHERE rfid_id = ?", (rfid_id,))
        self.conn.commit()

class AudioPlayer:
    def __init__(self, db: AudioBookDatabase):
        self.db = db
        self.playing = False
        self.current_rfid = None
        self.current_position = 0.0
        self.book_duration = 100.0  # Simulated duration in seconds for this example
        self.playback_thread = None

    def play(self, rfid_id, book_file):
        if self.playing:
            self.stop()

        self.current_rfid = rfid_id
        self.current_position = self.db.get_progress(rfid_id)
        self.playing = True

        self.playback_thread = Thread(target=self._playback_loop, args=(book_file,))
        self.playback_thread.start()

    def stop(self):
        if self.playing:
            self.playing = False
            if self.playback_thread:
                self.playback_thread.join()
            if self.current_rfid and self.current_position < self.book_duration:
                self.db.save_progress(self.current_rfid, self.current_position)

    def _playback_loop(self, book_file):
        # Simulating audio playback
        while self.playing and self.current_position < self.book_duration:
            time.sleep(1)
            self.current_position += 1.0

        # Delete the progress from the database when the book is finished
        if self.current_position >= self.book_duration:
            self.playing = False
            self.db.delete_progress(self.current_rfid)
            self.current_rfid = None

