import sys

def safe_fetch(url):
    # Conditionally import modules based on Python version behavior
    try:
        # Python 3
        from urllib.request import urlopen
        from urllib.error import URLError
    except ImportError:
        # Python 2
        from urllib2 import urlopen, URLError

    class CustomFetchError(Exception):
        pass

    def reraise_with_context(original_exc, message):
        """Custom function to re-raise exceptions safely across Python versions."""
        new_exc = CustomFetchError(message)

        if sys.version_info[0] >= 3:
            # Python 3 explicit exception chaining without causing SyntaxError in Python 2
            new_exc.__cause__ = original_exc
            new_exc.__traceback__ = original_exc.__traceback__
        else:
            # Python 2 fallback context preservation
            new_exc.args = ("{}: {}".format(message, original_exc),)

        raise new_exc

    try:
        response = urlopen(url)
        return response.read()
    except URLError as e:
        reraise_with_context(e, "Failed to fetch data from URL")
