public class AntlrRunner {
    public static void main(String[] args) {
        if (args.length < 2) {
            System.err.println("Usage: java AntlrRunner <directory> <file> [options...]");
            System.exit(1);
        }

        String directory = args[0];
        String file = args[1];

        List<String> command = new ArrayList<>();
        command.add("java");
        command.add("-cp");
        command.add(System.getProperty("java.class.path"));
        command.add("org.antlr.v4.Tool");

        for (int i = 2; i < args.length; i++) {
            command.add(args[i]);
        }

        command.add(file);

        try {
            ProcessBuilder pb = new ProcessBuilder(command);
            pb.directory(new File(directory));
            pb.redirectErrorStream(true);

            Process process = pb.start();

            try (BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    System.out.println(line);
                }
            }

            int exitCode = process.waitFor();

            if (exitCode != 0) {
                System.err.println("Error: ANTLR tool encountered errors and exited with code " + exitCode);
            }
        } catch (Exception e) {
            System.err.println("Exception occurred while running the ANTLR tool:");
            e.printStackTrace();
        }
    }
}
