import sys
import subprocess

def main():
    if len(sys.argv) < 2:
        sys.stderr.write("Error: No file path provided.\n")
        sys.exit(1)

    file_path = sys.argv[1]

    if len(sys.argv) > 2:
        command = sys.argv[2:]
    else:
        command = [sys.executable, '-m', 'json.tool']

    try:
        with open(file_path, 'rb') as f:
            file_content = f.read()
    except Exception as e:
        sys.stderr.write(f"Error reading file '{file_path}': {e}\n")
        sys.exit(1)

    try:
        process = subprocess.Popen(
            command,
            stdin=subprocess.PIPE,
            stdout=subprocess.DEVNULL,
            stderr=subprocess.PIPE
        )
        _, stderr_output = process.communicate(input=file_content)
    except FileNotFoundError:
        sys.stderr.write(f"Error: Command-line tool '{command[0]}' is not available.\n")
        sys.exit(1)
    except Exception as e:
        sys.stderr.write(f"Error: Failed to execute the tool properly: {e}\n")
        sys.exit(1)

    if process.returncode == 0:
        sys.exit(0)
    else:
        sys.stderr.write("Syntax validation failed.\n")
        if stderr_output:
            sys.stderr.write(stderr_output.decode('utf-8', errors='replace'))
        sys.exit(process.returncode)

