import hashlib
import os

def hash_message(message: str, hash_function: str, salt=None) -> str:
    if salt is None:
        salt = os.urandom(16)
    elif isinstance(salt, str):
        salt = salt.encode('utf-8')

    hasher = hashlib.new(hash_function.lower())
    hasher.update(salt + message.encode('utf-8'))

    return hasher.hexdigest()
