import requests

def post_and_delete(url, payload, query_params, target_key, target_value):
    post_response = requests.post(url, json=payload)
    delete_response = requests.delete(url, params=query_params)

    try:
        decoded_response = delete_response.json()
        if target_key in decoded_response and decoded_response[target_key] == target_value:
            return decoded_response
    except ValueError:
        pass

